// §11.6.1 PLANOVAC NIBE->bazen pro bazen_na_max (case 3)
// Vybere nejlevnejsich N hodin v horizontu podle pocitu potrebnych cyklu.
// Nastavi flow.pool_nibe_planned_now = true pokud aktualni hodina je v top-N.
const cfg = global.get("fve_config") || {};
// CRITICAL GUARD (§11.1): pool flow NESMI pracovat mimo letni rezim
if (cfg.letni_rezim !== true || cfg.pool_enabled !== true) {
    global.set("pool_nibe_planned_hours", []);
    flow.set("pool_nibe_planned_hours", []);
    flow.set("pool_nibe_planned_now", false);
    node.status({fill: "grey", shape: "ring", text: "off (letni/enabled)"});
    return msg;
}
const planData = global.get("fve_plan") || {};
const plan = Array.isArray(planData.plan) ? planData.plan : [];

function getFloat(id, def) {
    const s = global.get("homeassistant.homeAssistant.states['" + id + "']");
    if (!s) return def;
    const v = parseFloat(s.state);
    return isNaN(v) ? def : v;
}
function getBool(id, def) {
    const s = global.get("homeassistant.homeAssistant.states['" + id + "']");
    if (!s) return def;
    return s.state === "on";
}

const poolNaMax = getBool("input_boolean.bazen_na_max", false);
if (!poolNaMax || plan.length === 0) {
    flow.set("pool_nibe_planned_now", false);
    flow.set("pool_nibe_planned_hours", []);
    global.set("pool_nibe_planned_hours", []);
    node.status({fill: "grey", shape: "ring", text: "bazen_na_max=off"});
    return msg;
}

const vody = getFloat("sensor.hp2551ae_pro_v2_1_0_temperature_1", 20);
const cil = getFloat("input_number.pozadovana_teplota_v_bazenu", 28);
const deltaT = Math.max(0, cil - vody);
const cyklyPerDeg = cfg.pool_cykly_per_degree || 2;
const cyklesNeeded = Math.ceil(deltaT * cyklyPerDeg);
if (cyklesNeeded === 0) {
    flow.set("pool_nibe_planned_now", false);
    flow.set("pool_nibe_planned_hours", []);
    global.set("pool_nibe_planned_hours", []);
    node.status({fill: "green", shape: "ring", text: "cil dosazen " + vody.toFixed(1) + "°"});
    return msg;
}

const horizon = Math.min(cfg.pool_nibe_plan_horizon_h || 24, plan.length);
const window = plan.slice(0, horizon);
const sorted = window
    .map((p, idx) => ({ idx, price: parseFloat(p.priceBuy) }))
    .filter(x => !isNaN(x.price))
    .sort((a, b) => a.price - b.price);
const topIdxs = sorted.slice(0, cyklesNeeded).map(x => x.idx);
const plannedNow = topIdxs.includes(0);
flow.set("pool_nibe_planned_hours", topIdxs);
flow.set("pool_nibe_planned_now", plannedNow);
global.set("pool_nibe_planned_hours", topIdxs);  // §11.9 fve_plan integrace (B4)

node.status({fill: plannedNow?"blue":"grey", shape: "ring",
    text: "cyklu=" + cyklesNeeded + " top=[" + topIdxs.slice(0,6).join(",") + "]" + (plannedNow?" NOW":"")});
return msg;

// §11.6 NIBE -> bazen 4 use cases + 30 min runtime protection
// In:  msg (z planneru). Out: {action:"nibe_on"/"nibe_off"} nebo NULL (no-op).
// Flow: pool_nibe_running, pool_nibe_start_ts. Global: pool_heating_filtrace_lock_until.
const cfg = global.get("fve_config") || {};
if (cfg.letni_rezim !== true || cfg.pool_enabled !== true) {
    flow.set("pool_nibe_running", false);
    flow.set("pool_nibe_start_ts", 0);
    node.status({fill: "grey", shape: "ring", text: "OFF (letni/pool)"});
    return null;
}
function gF(id,d){const s=global.get("homeassistant.homeAssistant.states['"+id+"']");if(!s)return d;const v=parseFloat(s.state);return isNaN(v)?d:v;}
function gB(id,d){const s=global.get("homeassistant.homeAssistant.states['"+id+"']");if(!s)return d;return s.state==="on";}

const nibeOn = gB("switch.nibe_jednorazove_zvyseni_tuv", false);
const vody = gF("sensor.hp2551ae_pro_v2_1_0_temperature_1", 20);
const cil = gF("input_number.pozadovana_teplota_v_bazenu", 28);
const poolNaMax = gB("input_boolean.bazen_na_max", false);
const planData = global.get("fve_plan") || {};
const cur = (Array.isArray(planData.plan) && planData.plan.length) ? planData.plan[0] : {};
const buyPrice = parseFloat(cur.priceBuy);
const fveMode = global.get("fve_current_mode") || (planData.current_mode || "");
const solarRemE = global.get("homeassistant.homeAssistant.states['sensor.energy_production_today_remaining_3']") || {};
const solarRem = parseFloat(solarRemE.state) || 0;

const now = Date.now();
const startTs = flow.get("pool_nibe_start_ts") || 0;
const runSec = (nibeOn && startTs) ? (now - startTs) / 1000 : 0;
const minRun = cfg.pool_nibe_min_runtime_sec || 1800;
const canStop = runSec >= minRun;

// 1) STROP VODY: povinny dobeh min_runtime, pak off
if (vody >= cil) {
    if (nibeOn && !canStop) {
        flow.set("pool_nibe_running", true);
        global.set("pool_heating_filtrace_lock_until", now + 70000 + (cfg.pool_filtrace_cooldown_min||10)*60000);
        node.status({fill:"red",shape:"dot",text:"CIL "+vody.toFixed(1)+"° dobeh "+Math.round(minRun-runSec)+"s"});
        return null;
    }
    if (nibeOn) {
        flow.set("pool_nibe_running", false); flow.set("pool_nibe_start_ts", 0);
        node.status({fill:"green",shape:"dot",text:"CIL "+vody.toFixed(1)+"° → OFF"});
        return {action: "nibe_off"};
    }
    flow.set("pool_nibe_running", false);
    node.status({fill:"green",shape:"ring",text:"CIL "+vody.toFixed(1)+"° (off)"});
    return null;
}

// 2) USE CASES (§11.6)
const c1 = !isNaN(buyPrice) && buyPrice <= (cfg.pool_nibe_zaporna_cena_threshold ?? 0);
const c2 = (fveMode === "zakaz_pretoku") && (solarRem >= (cfg.pool_nibe_zakaz_pretoku_solar_kwh || 13));
const c3 = poolNaMax && (flow.get("pool_nibe_planned_now") === true);
const c4 = poolNaMax && !isNaN(buyPrice) && buyPrice <= (cfg.prah_ultra_levna_nakup || 1.0);
const any = c1 || c2 || c3 || c4;
const tag = c1?"zap":c2?"zak":c3?"plan":c4?"ultra":"-";

let action = null; let reason = "";
if (!nibeOn && any) {
    flow.set("pool_nibe_start_ts", now); flow.set("pool_nibe_running", true);
    action = "nibe_on"; reason = "→ON "+tag+(isNaN(buyPrice)?"":" "+buyPrice.toFixed(2)+"Kc");
} else if (nibeOn && !any && canStop) {
    flow.set("pool_nibe_running", false); flow.set("pool_nibe_start_ts", 0);
    action = "nibe_off"; reason = "→OFF no-case "+Math.round(runSec/60)+"m";
} else if (nibeOn && !any && !canStop) {
    flow.set("pool_nibe_running", true);
    reason = "dobeh "+Math.round(minRun-runSec)+"s";
} else if (nibeOn && any) {
    flow.set("pool_nibe_running", true);
    reason = "run "+Math.round(runSec/60)+"m "+tag;
}
if (nibeOn || action === "nibe_on") {
    global.set("pool_heating_filtrace_lock_until", now + 70000 + (cfg.pool_filtrace_cooldown_min||10)*60000);
}
const fill = (action==="nibe_on")?"blue":(action==="nibe_off")?"yellow":(nibeOn?"blue":"grey");
const shape = (nibeOn||action==="nibe_on")?"dot":"ring";
node.status({fill,shape,text:(action?action.toUpperCase()+" | ":"")+reason+" v="+vody.toFixed(1)+"° cil="+cil.toFixed(1)});
return action ? {action} : null;

// POOL Heating — data collect trigger (60s).
// V B2 vsechno ctene v decision func z global.get (homeassistant state).
// Tento node zatim jen trigger propaguje. V pripadnych optimalizacich (B3)
// by sem slo pridat pre-fetch a aggregaci.
msg.payload = {ts: Date.now()};
return msg;

// POOL Heating — guard + cteni stavu + stropy (§11.3)
// Vystup: msg { cfg, data, stropReason } -> pool_decide_logic.
// Pokud guard zablokuje (zimni rezim / pool_enabled=off), vrati null (flow konci).

const cfg = global.get("fve_config") || {};

// Guard: letni_rezim + pool_enabled
const letniRezim = cfg.letni_rezim === true;
const poolEnabled = cfg.pool_enabled === true;
if (!letniRezim || !poolEnabled) {
    flow.set("pool_patrony_allowed", false);
    flow.set("pool_patrony_max_floor", 0);
    node.status({fill: "grey", shape: "ring",
        text: "OFF (letni=" + (letniRezim?"1":"0") + " enabled=" + (poolEnabled?"1":"0") + ")"});
    return null;
}

// Helpery
function getFloat(id, def) {
    const s = global.get("homeassistant.homeAssistant.states['" + id + "']");
    if (!s) return def;
    const v = parseFloat(s.state);
    return isNaN(v) ? def : v;
}
function getBool(id, def) {
    const s = global.get("homeassistant.homeAssistant.states['" + id + "']");
    if (!s) return def;
    return s.state === "on";
}
function isAvail(id) {
    const s = global.get("homeassistant.homeAssistant.states['" + id + "']");
    return !!s && s.state !== "unavailable" && s.state !== "unknown";
}

// Stavove veliciny
const data = {
    teplotaVody:   getFloat("sensor.hp2551ae_pro_v2_1_0_temperature_1", 20),
    teplotaNadrz:  getFloat("sensor.teplota_smesovac_teplota", 20),
    solarW:        getFloat("sensor.vyroba_fve", 0),
    soc:           getFloat("sensor.battery_percent", 0),
    bCh:           getFloat("sensor.battery_dc_current", 0),
    autoMaHlad:    getBool("input_boolean.auto_ma_hlad", false),
    filtraceAvail: isAvail("switch.filtrace"),
    p1on:          getBool("switch.patrona_faze_1", false),
    p2on:          getBool("switch.patrona_faze_3_2", false),
    p3on:          getBool("switch.patrona_faze_3", false),
    ventilOn:      getBool("switch.bazen_ventil_smesovac", false),
    bojlerPower:   (function(){
        const c = global.get("homeassistant.homeAssistant.states['climate.smart_socket_thermostat_24090276694597600801c4e7ae0a2e53']");
        return (c && c.attributes && c.attributes.hvac_action === "heating") ? 2000 : 0;
    })(),  // §11.5 bod 6: konstanta 2 kW kdyz bojler topi (HA nema wattmetr)
};
data.activeFaze = (data.p1on?1:0) + (data.p2on?1:0) + (data.p3on?1:0);

// Stropy (§11.3)
let stropReason = null;
if (data.teplotaVody >= (cfg.pool_cilova_teplota_vody || 28)) {
    stropReason = "voda";  // cil -> patrony OFF + cooldown filtrace
} else if (data.teplotaNadrz >= (cfg.pool_max_teplota_nadrz || 60)) {
    stropReason = "nadrz"; // strop nadrze -> patrony OFF (NIBE neresi)
}

msg.cfg = cfg;
msg.data = data;
msg.stropReason = stropReason;
return msg;

// POOL Heating — rozhodovaci logika (§11.3/§11.5/§11.7)
// Vstup:  msg { cfg, data, stropReason }
// Vystup: msg.decision = { patronyAllowed, patronyMaxFloor, ventilAction,
//                          lockUntil, mod, statusText, statusFill }

const cfg = msg.cfg;
const data = msg.data;
const now = Date.now();
const filtraceCoolMin = cfg.pool_filtrace_cooldown_min || 10;

const dec = {
    patronyAllowed: false,
    patronyMaxFloor: 0,
    ventilAction: null,      // "on" / "off" / null
    lockUntil: null,         // ms
    mod: "Vypnuto",
    statusText: "",
    statusFill: "grey",
};

// STROP VODY -> patrony OFF + cooldown filtrace
if (msg.stropReason === "voda") {
    dec.ventilAction = data.ventilOn ? "off" : null;
    dec.lockUntil = now + filtraceCoolMin * 60000;
    dec.mod = "Vypnuto";
    dec.statusFill = "green";
    dec.statusText = "CIL voda=" + data.teplotaVody.toFixed(1) + "° cooldown " + filtraceCoolMin + "m";
    msg.decision = dec;
    return msg;
}
// STROP NADRZE -> patrony OFF (NIBE neresi — topi primo)
if (msg.stropReason === "nadrz") {
    dec.statusFill = "red";
    dec.statusText = "MAX NADRZ " + data.teplotaNadrz.toFixed(1) + "°";
    msg.decision = dec;
    return msg;
}

// PATRONY PODMINKY (§11.5 + §11.7)
const auto    = !data.autoMaHlad;
const socOk   = data.soc >= (cfg.topeni_min_soc_patron || 90);
const solarOk = data.solarW >= (cfg.topeni_patron_min_solar_w || 5000);
// §11.5 bod 6: bojler soubeh vyjimka — pokud vyroba pokryje oba, muzou bezet soucasne
const bojlerActivelyHeating = data.bojlerPower > 500;  // W
const bojlerOk = !bojlerActivelyHeating
    || (data.solarW - data.bojlerPower) >= (cfg.topeni_patron_min_solar_w || 5000);
dec.patronyAllowed = auto && socOk && solarOk && bojlerOk;
dec.patronyMaxFloor = dec.patronyAllowed ? 3 : 0;

// VENTIL HYSTEREZE (§11.3)
const minNadrz = cfg.pool_min_teplota_nadrz || 30;
const ventilStartC = cfg.pool_ventil_start_c || 50;
if (data.ventilOn) {
    if (data.teplotaNadrz < minNadrz) dec.ventilAction = "off";
} else {
    if (data.teplotaNadrz >= ventilStartC) dec.ventilAction = "on";
}
// Ventil ON vyzaduje dostupnou filtraci (§11.5 bod 8)
if (dec.ventilAction === "on" && !data.filtraceAvail) {
    dec.ventilAction = null;
}

// FILTRACE LOCK (§11.4): pokud ventil bude/je ON -> prodluz lock
const ventilActiveAfter = (dec.ventilAction === "on") || (data.ventilOn && dec.ventilAction !== "off");
if (ventilActiveAfter) {
    dec.lockUntil = now + 60000 + filtraceCoolMin * 60000;
}

// TOPENI_MOD (§11.9)
const nibeRunAfter = flow.get("pool_nibe_running") === true;  // B3
if (dec.patronyAllowed && nibeRunAfter) dec.mod = "BAZÉN - NIBE + Patrony";
else if (dec.patronyAllowed)            dec.mod = "BAZÉN - Patrony";
else if (nibeRunAfter)                  dec.mod = "BAZÉN - NIBE";

// STATUS
const reasons = [];
if (!dec.patronyAllowed) {
    if (!auto)     reasons.push("auto");
    if (!socOk)    reasons.push("SOC<" + (cfg.topeni_min_soc_patron || 90));
    if (!solarOk)  reasons.push("solar<" + (cfg.topeni_patron_min_solar_w || 5000));
    if (!bojlerOk) reasons.push("bojler=" + Math.round(data.bojlerPower) + "W");
}
dec.statusFill = dec.patronyAllowed ? "green" : "grey";
dec.statusText = (dec.patronyAllowed ? "ALLOWED max=" + dec.patronyMaxFloor + "f"
                                      : "BLOCKED:" + reasons.join(","))
    + " v=" + data.teplotaVody.toFixed(1) + "° n=" + data.teplotaNadrz.toFixed(1)
    + "° SOC=" + data.soc.toFixed(0) + "%";

msg.decision = dec;
return msg;

// POOL Heating — sestaveni vystupu + publikace flow state pro korekci (5s)
// Vstup:  msg.decision
// Vystupy:
//   1 -> ventil action   ({action: "ventil_on"/"ventil_off"} / null)
//   2 -> filtrace lock   ({payload: ms} / null)
//   3 -> topeni_mod sync ({payload: "BAZÉN - ..."/"Vypnuto"})
// POZN.: NIBE se od B3 rozhoduje separatne v pool_nibe_decide (60s)

const dec = msg.decision;

// Flow state pro korekcni smycku (5s tick)
flow.set("pool_patrony_allowed", dec.patronyAllowed);
flow.set("pool_patrony_max_floor", dec.patronyMaxFloor);

// Status nodu (diagnostika v NR UI)
node.status({fill: dec.statusFill, shape: "dot", text: dec.statusText});

// Sestaveni 3 vystupu
const out = [null, null, null];
if (dec.ventilAction === "on")  out[0] = {action: "ventil_on"};
if (dec.ventilAction === "off") out[0] = {action: "ventil_off"};
if (dec.lockUntil !== null)     out[1] = {payload: dec.lockUntil};
out[2] = {payload: dec.mod};

return out;

// POOL Heating — patrony korekcni smycka (5s tick, analogie §8.5)
// Cte flow.pool_patrony_allowed + flow.pool_patrony_max_floor (nastavuje main 60s).
// Feedback na baterii (bCh): +nabiji -> pridej fazi; -vybiji -> uber fazi.
// Dead band (cfg.topeni_patron_dead_band_w) kolem 0 W — prevence oscilace.

const cfg = global.get("fve_config") || {};
// CRITICAL GUARD: pool flow NESMI sahat na patrony mimo letni rezim (§8.5 patri FVE Heating)
if (cfg.letni_rezim !== true || cfg.pool_enabled !== true) {
    node.status({fill: "grey", shape: "ring", text: "pool off (letni/enabled) — no-op"});
    return null;
}
const allowed = flow.get("pool_patrony_allowed") === true;
const maxFloor = flow.get("pool_patrony_max_floor") || 0;

function getFloat(id, def) {
    const s = global.get("homeassistant.homeAssistant.states['" + id + "']");
    if (!s) return def;
    const v = parseFloat(s.state);
    return isNaN(v) ? def : v;
}
function getBool(id, def) {
    const s = global.get("homeassistant.homeAssistant.states['" + id + "']");
    if (!s) return def;
    return s.state === "on";
}

// Aktualni stavy patron
const p1on = getBool("switch.patrona_faze_1", false);
const p2on = getBool("switch.patrona_faze_3_2", false);
const p3on = getBool("switch.patrona_faze_3", false);
const actFaze = (p1on?1:0) + (p2on?1:0) + (p3on?1:0);

function buildActions(target) {
    const want = [target >= 1, target >= 2, target >= 3];
    const cur = [p1on, p2on, p3on];
    const names = ["p1", "p2", "p3"];
    const acts = [];
    for (let i = 0; i < 3; i++) {
        if (want[i] && !cur[i]) acts.push({action: names[i] + "_on"});
        else if (!want[i] && cur[i]) acts.push({action: names[i] + "_off"});
    }
    return acts;
}

// KDYZ NEPOVOLENO -> vypni vse (naraz, vsechny akce)
if (!allowed) {
    if (actFaze === 0) {
        node.status({fill: "grey", shape: "ring", text: "korekce: idle (allowed=0)"});
        return null;
    }
    const acts = buildActions(0);
    node.status({fill: "yellow", shape: "dot", text: "korekce -> OFF vse (" + actFaze + "f)"});
    return {payload: acts};
}

// FEEDBACK NA bCh (kladny = nabiji, zaporny = vybiji)
const bCh = getFloat("sensor.battery_dc_current", 0);
const deadBand = cfg.topeni_patron_dead_band_w || 200;
// Jedna faze patrony = 3000 W (tj. prah pridat = +3 kW, prah ubrat = jakykoli vybij)

let target = actFaze;
let reason = "hold";

if (bCh > 3000 && actFaze < maxFloor) {
    // Silne nabijime -> pridat fazi (o 1 krok; korekce opakuje kazdych 5s)
    target = actFaze + 1;
    reason = "bCh=+" + Math.round(bCh) + "W > +3kW -> +1f";
} else if (bCh < -deadBand && actFaze > 0) {
    // Vybijime pres dead band -> ubrat fazi
    target = actFaze - 1;
    reason = "bCh=" + Math.round(bCh) + "W < -" + deadBand + "W -> -1f";
} else if (actFaze === 0 && maxFloor >= 1 && bCh >= -deadBand) {
    // Idle start (nevybijime pod dead band) -> zapni 1 fazi
    target = 1;
    reason = "idle start 1f";
}

target = Math.max(0, Math.min(target, maxFloor));
const acts = buildActions(target);

node.status({
    fill: target > 0 ? "green" : "grey",
    shape: "dot",
    text: "korekce " + actFaze + "->" + target + "f | " + reason + " | max=" + maxFloor,
});

if (acts.length === 0) return null;
return {payload: acts};
